package com.hospital.management.model;import java.time.LocalDateTime;
/** One medicine and its directions within a prescription. */public class PrescriptionItem {private Long prescriptionItemId,prescriptionId;private String medicineName,dosage,frequency,duration,route,instructions;private LocalDateTime createdAt;public Long getPrescriptionItemId(){return prescriptionItemId;}public void setPrescriptionItemId(Long v){prescriptionItemId=v;}public Long getPrescriptionId(){return prescriptionId;}public void setPrescriptionId(Long v){prescriptionId=v;}public String getMedicineName(){return medicineName;}public void setMedicineName(String v){medicineName=v;}public String getDosage(){return dosage;}public void setDosage(String v){dosage=v;}public String getFrequency(){return frequency;}public void setFrequency(String v){frequency=v;}public String getDuration(){return duration;}public void setDuration(String v){duration=v;}public String getRoute(){return route;}public void setRoute(String v){route=v;}public String getInstructions(){return instructions;}public void setInstructions(String v){instructions=v;}public LocalDateTime getCreatedAt(){return createdAt;}public void setCreatedAt(LocalDateTime v){createdAt=v;}}
